import psycopg2

def connect_to_db():
    conn = psycopg2.connect(
        host="localhost",
        database="your_database",
        user="your_username",
        password="your_password"
    )
    return conn

def search_users(**kwargs):
    conn = connect_to_db()
    cur = conn.cursor()

    query = """
        SELECT *
        FROM users
        WHERE 1=1
    """

    for key, value in kwargs.items():
        if key == 'username':
            query += f" AND username='{value}'"
        elif key == 'email':
            query += f" AND email='{value}'"
        elif key == 'role':
            query += f" AND role='{value}'"
        elif key == 'status':
            query += f" AND status='{value}'"

    cur.execute(query)
    users = cur.fetchall()
    conn.close()

    return users

# Example usage:
